import{_ as h,r as e,o as k,c as g,a as n,b as s,t as r,d as a,w as o,e as i}from"./app-d223f2a5.js";const m={},w={id:"frontmatter-title-관련",tabindex:"-1"},f=n("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),y={class:"table-of-contents"},v=i('<hr><h2 id="project-22-part-one" tabindex="-1"><a class="header-anchor" href="#project-22-part-one" aria-hidden="true">#</a> Project 22, part one</h2><p>We looked at MapKit back in project 16, and while maps work great for finding location at the large scale, they work much <em>less</em> well for small-scale location – when you’re inside buildings, or perhaps trying to measure distances in terms of centimeters.</p><p>The problem is that location <em>matters</em>. As Phyllis Schlafly said, “location is the key to most businesses, and the entrepreneurs typically build their reputation at a particular spot.” You’ve probably heard the saying “location, location, location”, which pretty much sums it up.</p><p>Well, today you’re going to learn about <em>micro-location</em>: the ability to detect very small distances between things, even when you’re inside. This is all made possible through Apple’s iBeacon technology, which are Bluetooth-powered devices that emit low-energy signals iOS can detect and act on.</p><p>The range is short – maybe 40 meters / 130 feet in a line of sight – but these devices use so little power that they can survive for years on a tiny battery. This makes them perfect for museums, schools, galleries, malls, and more.</p><p><strong>Today you have three topics to work through, and you’ll learn about <code>Core Location</code>, <code>CLBeaconRegion</code>, and more.</strong></p><h3 id="setting-up" tabindex="-1"><a class="header-anchor" href="#setting-up" aria-hidden="true">#</a> Setting up</h3>',8),b={class:"hint-container details"},_=n("summary",null,"Setting up",-1),q={href:"https://hackingwithswift.com/read/22/1/setting-up",target:"_blank",rel:"noopener noreferrer"},I=n("p",null,"Apple introduced iBeacon technology with iOS 7, and it helped make the Internet of Things hypefest even more stratospheric. In this project you're going to learn to detect and range beacons, which in turn means learning how to ask your user for their location. With this, you'll have all the tools required to make your own location-aware apps – just scatter a few beacons around your house!",-1),C=n("p",null,`If you don't have any iBeacons at home, that's OK because most people don't. Instead, I recommend you install the app "Locate Beacon" on your iPad or iPhone, because that comes with an iBeacon transmitter built in, making it perfect for testing. You also need an iOS device that's compatible with iBeacons, which means iPhone 5 or later, 3rd generation iPad or later, iPad Mini or later, or 5th generation iPod Touch or later. I'm afraid the iOS Simulator won't work, but you can at least follow along with the code. Please ensure you have Bluetooth enabled on your device.`,-1),x=n("p",null,`If you've never pushed an app to a real device before, you need to make sure you select the device from the list of destinations. You can do this by clicking where it says "Project22" to the right of the play and stop buttons, or by going to the Product menu and choosing Destination then selecting your device. If it comes up with "ineligible" it means your device is running an older version of iOS than your project is designed for, so you may need to go to your project settings (where you configure orientation) and change Deployment Target to match.`,-1),L=n("p",null,"Create a new Single View App project in Xcode then name it Project22. Let’s go!",-1),U=n("h3",{id:"requesting-location-core-location",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#requesting-location-core-location","aria-hidden":"true"},"#"),s(" Requesting location: Core Location")],-1),A={class:"hint-container details"},R=n("summary",null,"Requesting location: Core Location",-1),T={href:"https://hackingwithswift.com/read/22/2/requesting-location-core-location",target:"_blank",rel:"noopener noreferrer"},B=i('<p>It should come as no surprise that Apple considers a user&#39;s location to be private, and that means we need to ask for permission to use it. How you ask for permission depends on what you&#39;re trying to do: would you like the user&#39;s location only when your app is running, or would you like a user&#39;s location even when your app isn&#39;t running?</p><p>You might think that you&#39;d only ever want location access when your app is running. After all, what&#39;s the point in asking for information when your app isn&#39;t around to use it?</p><p>There are times you&#39;ll want both. For example, if you&#39;re creating a map app that shows users how to get from their current location to your nearest store, you&#39;ll only need their location when the app is being used. But if you&#39;re creating an app that needs to be woken up when the user reaches a location, then you&#39;ll need access even when the app isn&#39;t running – iOS monitors the user&#39;s location on your behalf and automatically starts your app as needed.</p><p>Using location when the app isn’t running is of course highly sensitive information, so Apple flags it up in three ways:</p><ol><li>If you request Always access, users will still get the chance to choose When In Use.</li><li>If they choose Always, iOS will automatically ask them again after a few days to confirm they still want to grant Always access.</li><li>When your app is using location data in the background the iOS UI will update to reflect that – users will know it’s happening.</li><li>Users can, at any point, go into the settings app and change from Always down to When In Use.</li></ol><p>In this app we’re going to request Always access so that our app can detect beacons in the background. Requesting location access requires a change to your apps Info.plist file, which is the property list file we first met way back in project 3. We need to add to that file the reason why we want the user’s location – a string that will be shown in the iOS UI when the user is being asked to accept or decline our request.</p><p>Because of the rules above, we need to add two keys: “Privacy - Location Always and When In Use Usage Description” and “Privacy - Location When In Use Usage Description”. So, please add them both now, make sure their types are set to String, then in the value fields enter some text to explain to users <em>why</em> you want their location. For example, &quot;We want to help you find your nearest store.&quot; When your user is prompted to grant location access, this text will be shown alongside Apple&#39;s own descriptive message.</p><figure><img src="https://www.hackingwithswift.com/img/books/hws/22-1.png" alt="When iOS requests location access users are likely to be suspicious, so make sure you explain why you want it." tabindex="0" loading="lazy"><figcaption>When iOS requests location access users are likely to be suspicious, so make sure you explain why you want it.</figcaption></figure><p>That&#39;s enough knowledge to get this app jump started, so open up Main.storyboard and place a label in there. Give it the custom font System Thin size 40, then give the text &quot;UNKNOWN&quot;. For constraints, please center it horizontally and vertically. Now create an outlet for it using the assistant editor, and name the outlet <code>distanceReading</code>.</p><p>That label will show one of four messages depending on how close we are to our test beacon, which of course might be an iPad acting as a beacon if you don&#39;t own actual hardware. Because iBeacons use very low energy levels, their range is limited and also easily interrupted; even something as simple as turning your back to the beacon weakens its signal dramatically. Based on the beacon&#39;s distance to us, we&#39;ll show either &quot;UNKNOWN&quot;, &quot;FAR&quot;, &quot;NEAR&quot; or &quot;RIGHT HERE&quot;.</p><p>Apple restricts your ranging to these values because of the signal&#39;s low energy nature, but it&#39;s more than enough for most uses.</p><figure><img src="https://www.hackingwithswift.com/img/books/hws/22-2.png" alt="Our user interface is just one label: how close is the user to the beacon?" tabindex="0" loading="lazy"><figcaption>Our user interface is just one label: how close is the user to the beacon?</figcaption></figure><p>To complete our current step, let&#39;s make sure we have location configured correctly. This bit will work fine on the simulator, because although the simulator isn&#39;t capable of detecting iBeacons it can simulate general location information well enough.</p>',13),j=n("code",null,"ViewController.swift",-1),S=i(`<div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">import</span> <span class="token class-name">CoreLocation</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Now add this property to your class:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">var</span> locationManager<span class="token punctuation">:</span> <span class="token class-name">CLLocationManager</span><span class="token operator">?</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>This is the Core Location class that lets us configure how we want to be notified about location, and will also deliver location updates to us.</p><p>That doesn&#39;t actually create a location manager, or even prompt the user for location permission! To do that, we first need to create the object (easy), then set ourselves as its delegate (easy, but we need to conform to the protocol), then finally we need to request authorization. We&#39;ll start by conforming to the protocol, so change your class definition to this:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">class</span> <span class="token class-name">ViewController</span><span class="token punctuation">:</span> <span class="token class-name">UIViewController</span><span class="token punctuation">,</span> <span class="token class-name">CLLocationManagerDelegate</span> <span class="token punctuation">{</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Now modify your viewDidLoad() method to this:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">override</span> <span class="token keyword">func</span> <span class="token function-definition function">viewDidLoad</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">super</span><span class="token punctuation">.</span><span class="token function">viewDidLoad</span><span class="token punctuation">(</span><span class="token punctuation">)</span>

    locationManager <span class="token operator">=</span> <span class="token class-name">CLLocationManager</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    locationManager<span class="token operator">?</span><span class="token punctuation">.</span>delegate <span class="token operator">=</span> <span class="token keyword">self</span>
    locationManager<span class="token operator">?</span><span class="token punctuation">.</span><span class="token function">requestAlwaysAuthorization</span><span class="token punctuation">(</span><span class="token punctuation">)</span>

    view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token punctuation">.</span>gray
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Creating the object and setting the delegate are easy enough, but the <code>requestAlwaysAuthorization()</code> call is new. This is where the actual action happens: if you have already been granted location permission then things will Just Work; if you haven&#39;t, iOS will request it now.</p><p>Note: if you used the &quot;when in use&quot; key, you should call <code>requestWhenInUseAuthorization()</code> instead. If you did not set the correct plist key earlier, your request for location access will be ignored.</p><p>I slipped one other thing in there: I set the view&#39;s background color to be gray. As well as changing the label&#39;s text, we&#39;ll be using color to tell users how distant the beacon is.</p><p>Requesting location authorization is a non-blocking call, which means your code will carry on executing while the user reads your location message and decides whether to grant you access to their location.</p><p>When the user has finally made their mind, you&#39;ll get told their result because we set ourselves as the delegate for our <code>CLLocationManager</code> object. The method that will be called is this one:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">func</span> <span class="token function-definition function">locationManager</span><span class="token punctuation">(</span><span class="token omit keyword">_</span> manager<span class="token punctuation">:</span> <span class="token class-name">CLLocationManager</span><span class="token punctuation">,</span> didChangeAuthorization status<span class="token punctuation">:</span> <span class="token class-name">CLAuthorizationStatus</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> status <span class="token operator">==</span> <span class="token punctuation">.</span>authorizedAlways <span class="token punctuation">{</span>
        <span class="token keyword">if</span> <span class="token class-name">CLLocationManager</span><span class="token punctuation">.</span><span class="token function">isMonitoringAvailable</span><span class="token punctuation">(</span><span class="token keyword">for</span><span class="token punctuation">:</span> <span class="token class-name">CLBeaconRegion</span><span class="token punctuation">.</span><span class="token keyword">self</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token keyword">if</span> <span class="token class-name">CLLocationManager</span><span class="token punctuation">.</span><span class="token function">isRangingAvailable</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
                <span class="token comment">// do stuff</span>
            <span class="token punctuation">}</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Put that into your view controller class somewhere, then run your app. It&#39;s important to test it before continuing, because if you&#39;ve made a mistake somewhere it&#39;s hard to know unless you stop and check. The most common error is misconfiguring the plist with location privacy settings, so if you don&#39;t see a message requesting location access then check there first.</p><p>The <code>didChangeAuthorization</code> method we just added doesn&#39;t do anything because it just has a comment saying<code> // do stuff</code>. We&#39;ll fill that in with great stuff shortly, but for now look at the conditional statements wrapped around it: did we get authorized by the user? If so, is our device able to monitor iBeacons? If so, is ranging available? (Ranging is the ability to tell roughly how far something else is away from our device.)</p>`,16),M=n("h3",{id:"hunting-the-beacon-clbeaconregion",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#hunting-the-beacon-clbeaconregion","aria-hidden":"true"},"#"),s(" Hunting the beacon: "),n("code",null,"CLBeaconRegion")],-1),N={class:"hint-container details"},O=n("summary",null,"Hunting the beacon: CLBeaconRegion",-1),W={href:"https://hackingwithswift.com/read/22/3/hunting-the-beacon-clbeaconregion",target:"_blank",rel:"noopener noreferrer"},D=i(`<p>If everything is working, you should have received a large iOS confirmation prompt asking whether you want to grant the app access to your location. This message is really blunt, so users hopefully take a few moments to read it before continuing.</p><p>But that prompt is not the only way iOS helps users guard their privacy. If you went for &quot;when in use&quot;, you&#39;ll still get location information while your app is in the background if you enable the background capability, and iOS will notify users that this is happening by making the device status bar blue and saying &quot;YourAppName is using your location.&quot; If you went for &quot;always&quot;, iOS will wait a few days then ask the user if they still want to grant permission, just to be fully sure.</p><p>Assuming everything went well, let&#39;s take a look at how we actually range beacons. First, we use a new class called <code>CLBeaconRegion</code>, which is used to identify a beacon uniquely. Second, we give that to our <code>CLLocationManager</code> object by calling its <code>startMonitoring(for:)</code> and <code>startRangingBeacons(in:)</code> methods. Once that&#39;s done, we sit and wait. As soon as iOS has anything tell us, it will do so.</p><p>iBeacons are identified using three pieces of information: a universally unique identifier (UUID), plus a major number and a minor number. The first number is a long hexadecimal string that you can create by running the <code>uuidgen</code> in your Mac&#39;s terminal. It should identify you or your store chain uniquely.</p><p>The major number is used to subdivide within the UUID. So, if you have 10,000 stores in your supermarket chain, you would use the same UUID for them all but give each one a different major number. That major number must be between 1 and 65535, which is enough to identify every McDonalds and Starbucks outlet combined!</p><p>The minor number can (if you wish) be used to subdivide within the major number. For example, if your flagship London store has 12 floors each of which has 10 departments, you would assign each of them a different minor number.</p><p>The combination of all three identify the user&#39;s precise location:</p><ul><li><strong>UUID</strong>: You&#39;re in a Acme Hardware Supplies store.</li><li><strong>Major</strong>: You&#39;re in the Glasgow branch.</li><li><strong>Minor</strong>: You&#39;re in the shoe department on the third floor.</li></ul><p>If you don&#39;t need that level of detail you can skip minor or even major – it&#39;s down to you.</p><p>It&#39;s time to put this into code, so we&#39;re going to create a new method called <code>startScanning()</code> that contains the following:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">func</span> <span class="token function-definition function">startScanning</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">let</span> uuid <span class="token operator">=</span> <span class="token function">UUID</span><span class="token punctuation">(</span>uuidString<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;5A4BCFCE-174E-4BAC-A814-092E77F6B7E5&quot;</span></span><span class="token punctuation">)</span><span class="token operator">!</span>
    <span class="token keyword">let</span> beaconRegion <span class="token operator">=</span> <span class="token class-name">CLBeaconRegion</span><span class="token punctuation">(</span>proximityUUID<span class="token punctuation">:</span> uuid<span class="token punctuation">,</span> major<span class="token punctuation">:</span> <span class="token number">123</span><span class="token punctuation">,</span> minor<span class="token punctuation">:</span> <span class="token number">456</span><span class="token punctuation">,</span> identifier<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&quot;MyBeacon&quot;</span></span><span class="token punctuation">)</span>

    locationManager<span class="token operator">?</span><span class="token punctuation">.</span><span class="token function">startMonitoring</span><span class="token punctuation">(</span><span class="token keyword">for</span><span class="token punctuation">:</span> beaconRegion<span class="token punctuation">)</span>
    locationManager<span class="token operator">?</span><span class="token punctuation">.</span><span class="token function">startRangingBeacons</span><span class="token punctuation">(</span><span class="token keyword">in</span><span class="token punctuation">:</span> beaconRegion<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>You met <code>UUID</code> in project 10, but here we&#39;re converting a string into a UUID rather than generating a UUID and converting it to a string. The UUID I&#39;m using there is one of the ones that comes built into the Locate Beacon app – look under &quot;Apple AirLocate 5A4BCFCE&quot; and find it there. Note that I&#39;m scanning for specific major and minor numbers, so please enter those into your Locate Beacon app.</p><p>The <code>identifier</code> field is just a string you can set to help identify this beacon in a human-readable way. That, plus the UUID, major and minor fields, goes into the <code>CLBeaconRegion</code> class, which is used to identify and work with iBeacons. It then gets sent to our location manager, asking it to monitor for the existence of the region and also to start measuring the distance between us and the beacon.</p><p>Find the <code>// do stuff</code> comment inside the <code>didChangeAuthorization</code> method you wrote a few minutes ago, and change it to this:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token function">startScanning</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>That method should now be much clearer: we only start scanning for beacons when we have permission and if the device is able to do so.</p><p>If you run the app now (on a real device, remember!) you&#39;ll see that it literally looks identical, as if we needn&#39;t have bothered writing any iBeacon code. But behind the scenes, detection and ranging <em>is</em> happening, we&#39;re just not doing anything with it!</p><p>This app is going to change the label text and view background color to reflect proximity to the beacon we&#39;re scanning for. This will be done in a single method, called <code>update(distance:)</code>, which will use a switch/case block and animations in order to make the transition look smooth. Let&#39;s write that method first:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">func</span> <span class="token function-definition function">update</span><span class="token punctuation">(</span>distance<span class="token punctuation">:</span> <span class="token class-name">CLProximity</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token class-name">UIView</span><span class="token punctuation">.</span><span class="token function">animate</span><span class="token punctuation">(</span>withDuration<span class="token punctuation">:</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">switch</span> distance <span class="token punctuation">{</span>
        <span class="token keyword">case</span> <span class="token punctuation">.</span>unknown<span class="token punctuation">:</span>
            <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token class-name">UIColor</span><span class="token punctuation">.</span>gray
            <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;UNKNOWN&quot;</span></span>

        <span class="token keyword">case</span> <span class="token punctuation">.</span>far<span class="token punctuation">:</span>
            <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token class-name">UIColor</span><span class="token punctuation">.</span>blue
            <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;FAR&quot;</span></span>

        <span class="token keyword">case</span> <span class="token punctuation">.</span>near<span class="token punctuation">:</span>
            <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token class-name">UIColor</span><span class="token punctuation">.</span>orange
            <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;NEAR&quot;</span></span>

        <span class="token keyword">case</span> <span class="token punctuation">.</span>immediate<span class="token punctuation">:</span>
            <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token class-name">UIColor</span><span class="token punctuation">.</span>red
            <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;RIGHT HERE&quot;</span></span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Most of that is just choosing the right color and text, but you&#39;ll notice the method accepts a <code>CLProximity</code> as its parameter.</p><p>Now, in theory this can only be be one of our four distance values, which is why we have a <code>default</code> case in there. However, Swift should show you a warning because Apple has marked <code>CLProximity</code> as an enum that might change in the future – they might add more fine-grained values, for example.</p><p>This is only a <em>warning</em> rather than an <em>error</em> because you can build ship your code without covering future cases if you want to. However, if you do that you risk running into problems in the future: if Apple added an extra <code>.farFarAway</code> case in there, what would your code do?</p><p>There are two solutions here: we can add a special case called <code>@unknown default</code>, which is specifically there to catch future values. This allows you to cover all the other cases explicitly, then provide one extra case to handle as-yet-unknown cases in the future:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token attribute atrule">@unknown</span> <span class="token keyword">default</span><span class="token punctuation">:</span>
    <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token punctuation">.</span>black
    <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;WHOA!&quot;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>In this app, though, it’s easier to treat unknown future cases as a regular unknown case, so instead I would recommend you write this:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">func</span> <span class="token function-definition function">update</span><span class="token punctuation">(</span>distance<span class="token punctuation">:</span> <span class="token class-name">CLProximity</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token class-name">UIView</span><span class="token punctuation">.</span><span class="token function">animate</span><span class="token punctuation">(</span>withDuration<span class="token punctuation">:</span> <span class="token number">0.8</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">switch</span> distance <span class="token punctuation">{</span>
        <span class="token keyword">case</span> <span class="token punctuation">.</span>far<span class="token punctuation">:</span>
            <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token class-name">UIColor</span><span class="token punctuation">.</span>blue
            <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;FAR&quot;</span></span>

        <span class="token keyword">case</span> <span class="token punctuation">.</span>near<span class="token punctuation">:</span>
            <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token class-name">UIColor</span><span class="token punctuation">.</span>orange
            <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;NEAR&quot;</span></span>

        <span class="token keyword">case</span> <span class="token punctuation">.</span>immediate<span class="token punctuation">:</span>
            <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token class-name">UIColor</span><span class="token punctuation">.</span>red
            <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;RIGHT HERE&quot;</span></span>

        <span class="token keyword">default</span><span class="token punctuation">:</span>
            <span class="token keyword">self</span><span class="token punctuation">.</span>view<span class="token punctuation">.</span>backgroundColor <span class="token operator">=</span> <span class="token class-name">UIColor</span><span class="token punctuation">.</span>gray
            <span class="token keyword">self</span><span class="token punctuation">.</span>distanceReading<span class="token punctuation">.</span>text <span class="token operator">=</span> <span class="token string-literal"><span class="token string">&quot;UNKNOWN&quot;</span></span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>With that method written, all that remains before our project is complete is to catch the ranging method from <code>CLLocationManager</code>. We&#39;ll be given the array of beacons it found for a given region, which allows for cases where there are multiple beacons transmitting the same UUID.</p><p>If we receive any beacons from this method, we&#39;ll pull out the first one and use its proximity <code>property</code> to call our <code>update(distance:)</code> method and redraw the user interface. If there aren&#39;t any beacons, we&#39;ll just use <code>.unknown</code>, which will switch the text back to &quot;UNKNOWN&quot; and make the background color gray.</p><p>Here&#39;s the code:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code><span class="token keyword">func</span> <span class="token function-definition function">locationManager</span><span class="token punctuation">(</span><span class="token omit keyword">_</span> manager<span class="token punctuation">:</span> <span class="token class-name">CLLocationManager</span><span class="token punctuation">,</span> didRangeBeacons beacons<span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token class-name">CLBeacon</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token keyword">in</span> region<span class="token punctuation">:</span> <span class="token class-name">CLBeaconRegion</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token keyword">let</span> beacon <span class="token operator">=</span> beacons<span class="token punctuation">.</span>first <span class="token punctuation">{</span>
        <span class="token function">update</span><span class="token punctuation">(</span>distance<span class="token punctuation">:</span> beacon<span class="token punctuation">.</span>proximity<span class="token punctuation">)</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
        <span class="token function">update</span><span class="token punctuation">(</span>distance<span class="token punctuation">:</span> <span class="token punctuation">.</span>unknown<span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>With that, your code is done. Run it on a device, make sure Locate Beacon is up and transmitting, and enjoy your location-aware app!</p>`,31),P=n("hr",null,null,-1);function z(p,E){const t=e("router-link"),c=e("ExternalLinkIcon"),l=e("YouTube"),u=e("FontIcon"),d=e("TagLinks");return k(),g("div",null,[n("h1",w,[f,s(" "+r(p.$frontmatter.title)+" 관련",1)]),n("blockquote",null,[n("p",null,r(p.$frontmatter.description),1)]),n("nav",y,[n("ul",null,[n("li",null,[a(t,{to:"#project-22-part-one"},{default:o(()=>[s("Project 22, part one")]),_:1}),n("ul",null,[n("li",null,[a(t,{to:"#setting-up"},{default:o(()=>[s("Setting up")]),_:1})]),n("li",null,[a(t,{to:"#requesting-location-core-location"},{default:o(()=>[s("Requesting location: Core Location")]),_:1})]),n("li",null,[a(t,{to:"#hunting-the-beacon-clbeaconregion"},{default:o(()=>[s("Hunting the beacon: CLBeaconRegion")]),_:1})])])])])]),v,n("details",b,[_,n("p",null,[n("a",q,[s("📎link"),a(c)])]),a(l,{id:"y9GGNzc-T-4"}),I,C,x,L]),U,n("details",A,[R,n("p",null,[n("a",T,[s("📎link"),a(c)])]),a(l,{id:"Oz5vxVIKIqU"}),B,n("p",null,[s("Open "),a(u,{icon:"fas fa-dove"}),j,s(" and add this import alongside UIKit:")]),S]),M,n("details",N,[O,n("p",null,[n("a",W,[s("📎link"),a(c)])]),a(l,{id:"HcS4U4aOeCI"}),D]),P,a(d)])}const F=h(m,[["render",z],["__file","75.html.vue"]]);export{F as default};
